  "embedding": [0.1, 0.2, ...]
}
```

2. **Custom Scoring Function:**
   - Use a custom scoring function to combine BM25 and embedding similarity.

```json
GET /_search
{
  "_source": ["*"],
  "query": {
    "function_score": {
      "query": {
        "match": { "text": "example query" }
      },
      "functions": [
        {
          "script_score": {
            "script": {
              "source": "cosineSimilarity(params.query_vector, doc['embedding'])",
              "params": {
                "query_vector": [0.1, 0.2, ...] // Query embedding
              }
            }
